arguments.command:
set -euo pipefail
trial=$(mktemp -d /tmp/nix-jj-override-probe.XXXXXX)
trap 'rm -rf "$trial"' EXIT
native="$trial/native"; published="$trial/published"; remote="$trial/remote"; consumer="$trial/consumer"
probe_flake='{
  outputs = { self }: let s = self.outPath; e = p: if builtins.pathExists p then builtins.attrNames (builtins.readDir p) else []; in {
    sourceSummary = { rootEntries = e s; jjEntries = e "${s}/.jj"; workspaceNoisePresent = builtins.pathExists "${s}/workspace-noise"; };
  };
}'
mkdir -p "$native"; jj git init --no-colocate "$native" >/dev/null; printf '%b\n' "$probe_flake" >"$native/flake.nix"; mkdir -p "$native/workspace-noise"; printf ignored-but-copied >"$native/workspace-noise/noise.txt"
jj git init "$published" >/dev/null; printf '%b\n' "$probe_flake" >"$published/flake.nix"; printf 'workspace-noise/\n' >"$published/.gitignore"; jj -R "$published" commit -m 'seed published probe' >/dev/null; jj -R "$published" bookmark create main -r @- >/dev/null; mkdir -p "$published/workspace-noise"; printf ignored-and-not-published >"$published/workspace-noise/noise.txt"
jj git init --no-colocate "$remote" >/dev/null; jj -R "$published" git remote add origin "$remote/.jj/repo/store/git"; jj -R "$published" git push --remote origin --bookmark main >/dev/null
rev=$(jj -R "$published" log -r main --no-graph -T 'commit_id')
remote_url="git+file://$remote/.jj/repo/store/git?ref=main&rev=$rev"
mkdir -p "$consumer"
cat >"$consumer/flake.nix" <<EOF
{
  inputs.probe.url = "$remote_url";
  outputs = { probe, ... }: { probeSourceSummary = probe.sourceSummary; };
}
EOF
printf 'without override (pushed pinned Git input): '
nix eval --no-write-lock-file --json "path:$consumer#probeSourceSummary"
printf '\nwith --override-input probe path:<native non-colocated Jujutsu workspace>: '
nix eval --no-write-lock-file --override-input probe "path:$native" --json "path:$consumer#probeSourceSummary"
printf '\nDisposable override probe removed at process exit.\n'

